sql:
SELECT p_value_id
FROM p_values
WHERE measurement_id = 1;

SELECT s.study_name, s.status
FROM studies s
WHERE s.study_id NOT IN (
  SELECT p.study_id
  FROM publications p
);

SELECT study_id, COUNT(group_id) AS num_groups 
FROM groups 
GROUP BY study_id;

SELECT ROUND(AVG(p_value), 2) 
FROM p_values 
WHERE p_value <= 0.05;

SELECT title 
FROM publications 
WHERE year = 2020 AND doi LIKE '10.1001/%';

SELECT AVG(value) AS average_value, group_id
FROM measurement_values
GROUP BY group_id;

SELECT AVG(value) AS average_value
FROM measurement_values
WHERE measurement_id = 0;

SELECT COUNT(publication_id) 
FROM publications 
WHERE study_id = (SELECT study_id FROM studies WHERE study_name = 'Study 2');

SELECT COUNT(*) 
FROM researchers 
WHERE study_id = (SELECT study_id FROM studies WHERE study_name = 'Study 1');

SELECT COUNT(DISTINCT researcher_id) 
FROM researcher_publications 
WHERE contribution = 'primary author';

SELECT COUNT(*) 
FROM measurements m 
WHERE m.study_id IN (SELECT s.study_id FROM studies s WHERE s.status = 'completed');
